+//! WASM bindings for Zero-Knowledge Financial Proofs
+//!
+//! Generate and verify ZK proofs entirely in the browser.
+
+#![cfg(feature = "wasm")]
+
+use wasm_bindgen::prelude::*;
+use serde::{Deserialize, Serialize};
+
+use super::zkproofs::{
