+/// Verification result
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct VerificationResult {
+    /// Whether the proof is valid
+    pub valid: bool,
+    /// The statement that was verified
+    pub statement: String,
+    /// When verification occurred
+    pub verified_at: u64,
+    /// Any error message
+    pub error: Option<String>,
+}
